import {
  betti1Proxy,
  RollbackController,
  type EffectiveGraphSnapshot,
} from '../socio-topology/index';

const triangle: EffectiveGraphSnapshot = {
  nodeCount: 3,
  edges: [
    { u: 0, v: 1 },
    { u: 1, v: 2 },
    { u: 0, v: 2 },
  ],
  t: 0,
};

if (betti1Proxy(triangle) !== 1) {
  throw new Error(`triangle β₁ expected 1, got ${betti1Proxy(triangle)}`);
}

const policy = {
  lambda2Star: 10,
  tauWindows: 2,
  integralBudgetW: 100,
  beta1Min: 0,
};

const c = new RollbackController(policy);
if (c.step({ lambda2Hat: 9, beta1Hat: 5, t: 0 }).action !== 'hold') throw new Error('expected hold');
if (c.step({ lambda2Hat: 9, beta1Hat: 5, t: 1 }).action !== 'rollback') throw new Error('expected consecutive rollback');

const policyIntegral = { ...policy, tauWindows: 999 };
const c2 = new RollbackController(policyIntegral);
for (let i = 0; i < 60; i++) {
  const d = c2.step({ lambda2Hat: 8, beta1Hat: 5, t: i });
  if (d.action === 'rollback' && d.reason === 'integral_deficit') break;
  if (i === 59) throw new Error('expected integral rollback');
}

const c3 = new RollbackController({ ...policy, beta1Min: 5 });
if (c3.step({ lambda2Hat: 20, beta1Hat: 0, t: 0 }).reason !== 'betti_floor') {
  throw new Error('expected betti rollback');
}
